9089 bool SimplifyCFGOpt::simplifyOnce(BasicBlock *BB) {
9090   bool Changed = false;
9091 
9092   assert(BB && BB->getParent() && "Block not embedded in function!");
9093   assert(BB->getTerminator() && "Degenerate basic block encountered!");
