9096   // or that just have themself as a predecessor.  These are unreachable.
9097   if ((pred_empty(BB) && BB != &BB->getParent()->getEntryBlock()) ||
9098       BB->getSinglePredecessor() == BB) {
9099     LLVM_DEBUG(dbgs() << "Removing BB: \n" << *BB);
9100     DeleteDeadBlock(BB, DTU);
