9102   }
9103 
9104   // Check to see if we can constant propagate this terminator instruction
9105   // away...
9106   Changed |= ConstantFoldTerminator(BB, /*DeleteDeadConditions=*/true,
9107                                     /*TLI=*/nullptr, DTU);
9108 
9109   // Check for and eliminate duplicate PHI nodes in this block.
9110   Changed |= EliminateDuplicatePHINodes(BB);
9111 
9112   // Check for and remove branches that will always cause undefined behavior.
9113   if (removeUndefIntroducingPredecessor(BB, DTU, Options.AC))
9114     return requestResimplify();
