9123     if (sinkCommonCodeFromPredecessors(BB, DTU) ||
9124         mergeCompatibleInvokes(BB, DTU)) {
9125       // sinkCommonCodeFromPredecessors() does not automatically CSE PHI's,
9126       // so we may now how duplicate PHI's.
9127       // Let's rerun EliminateDuplicatePHINodes() first,
9128       // before foldTwoEntryPHINode() potentially converts them into select's,
9129       // after which we'd need a whole EarlyCSE pass run to cleanup them.
9130       return true;
9131     }
9132 
