9172 bool SimplifyCFGOpt::run(BasicBlock *BB) {
9173   bool Changed = false;
9174 
9175   // Repeated simplify BB as long as resimplification is requested.
9176   do {
9177     Resimplify = false;
9178 
9179     // Perform one round of simplifcation. Resimplify flag will be set if
9180     // another iteration is requested.
9181     Changed |= simplifyOnce(BB);
9182   } while (Resimplify);
